if (event.getPacket() instanceof C01PacketChatMessage) {
  C01PacketChatMessage packet = (C01PacketChatMessage) event.getPacket();
  String msg = packet.getMessage();
  // Don"t bypass commands
  if (!msg.startsWith("/")) {
    event.setCancelled(true);  // cancel original
    String bypassed = bypass(msg);  // apply bypass transformations
    mc.getNetHandler().getNetworkManager().sendPacketNoEvent(new C01PacketChatMessage(bypassed));
  }
}

private String bypass(String s) {
  // Example: replace letters with lookalikes
  return s.replace("a", "ɑ").replace("e", "ɛ");
}
